const input = $input.first().json;
const body = input.body ?? input;

const question  = (body.question || '').trim();
let userEmail = (body.user_email || '').trim().toLowerCase();

// 🧪 TEST fallback
if (!userEmail && body.user === 'test') {
  userEmail = 'test@ceg.hu';
}
const userRole  = (body.user_role || 'employee').trim().toLowerCase();

const allowedDomains = ['ceg.hu'];
const requireInternalEmail = true;
const maxQuestionLength = 500;

// --- VALIDÁCIÓK ---

if (!question) {
  throw new Error('Hiányzó kérdés (question mező üres)');
}

if (question.length > maxQuestionLength) {
  throw new Error(`A kérdés túl hosszú. Maximum ${maxQuestionLength} karakter engedélyezett.`);
}

if (!userEmail || !userEmail.includes('@')) {
  throw new Error('Hiányzó vagy érvénytelen user_email');
}

const emailDomain = userEmail.split('@')[1];

if (requireInternalEmail && !allowedDomains.includes(emailDomain)) {
  throw new Error('Unauthorized email domain');
}

// --- ROLE FILTER ---

const roleMap = {
  admin:    ['hr', 'legal', 'ops', 'finance', 'general'],
  manager:  ['hr', 'ops', 'finance', 'general'],
  employee: ['hr', 'general'],
  guest:    ['general'],
};

const allowedTags = roleMap[userRole] || roleMap['guest'];

// --- LANGUAGE DETECTION ---

const lang =
  /[áéíóöőúüű]/i.test(question) ? 'hu'
  : /\b(urlaub|vertrag|richtlinie|prozess|abrechnung|personal|regelung)\b/i.test(question) ? 'de'
  : 'auto';

// --- OUTPUT ---

return [{
  json: {
    question,
    userEmail,
    userRole,
    allowedTags,
    requestId: `req_${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
    timestamp: new Date().toISOString(),
    language: lang,
    startedAtMs: Date.now(),
    maxQuestionLength
  }
}];

const base = $('Validate + Auth + Role Filter').first().json;

return [{
  json: {
    question:         base.question,
    userEmail:        base.userEmail,
    userRole:         base.userRole,
    allowedTags:      base.allowedTags,
    requestId:        base.requestId,
    timestamp:        base.timestamp,
    language:         base.language,
    startedAtMs:      base.startedAtMs,
    maxQuestionLength: base.maxQuestionLength,
    enrichedQuery:    base.question
  }
}];

const req = $('Query Merge').first().json;
const embedData = $input.first().json;
const embedding = embedData.data?.[0]?.embedding || [];
if (!embedding.length) {
  throw new Error('Nem sikerült embeddinget generálni.');
}

const limit = 5;
// const scoreThreshold = 0.75;
const scoreThreshold = 0;

const strictBody = {
  vector: embedding,
  limit,
  score_threshold: scoreThreshold,
  with_payload: true,
  with_vectors: false,
  filter: {
    must: [{
      key: 'tag',
      match: { any: req.allowedTags || ['general'] }
    }]
  }
};

const relaxedBody = {
  vector: embedding,
  limit,
  score_threshold: Math.max(0.55, scoreThreshold - 0.15),
  with_payload: true,
  with_vectors: false
};

return [{
  json: {
    ...req,
    embedding,
    strictQdrantBody: JSON.stringify(strictBody),
    relaxedQdrantBody: JSON.stringify(relaxedBody),
    strictScoreThreshold: scoreThreshold,
    relaxedScoreThreshold: Math.max(0.55, scoreThreshold - 0.15)
  }
}];

const req = $('build-qdrant-queries').item.json;
const strictResp = $('qdrant-search-strict').item.json;
const relaxedResp = $input.item.json;

const strictResults = strictResp.result || [];
const relaxedResults = relaxedResp.result || [];

const usingFallback = strictResults.length === 0;
const results = usingFallback ? relaxedResults : strictResults;

return [{
  json: {
    ...req,
    qdrantResults: results,
    usingFallback,
    retrievalMode: usingFallback ? 'relaxed' : 'strict'
  }
}];

const req = $('Qdrant Query Builder').first().json;
const strictResp = $input.first().json;
const strictResults = strictResp.result || [];

return [{
  json: {
    ...req,
    qdrantResults: strictResults,
    usingFallback: false,
    retrievalMode: 'strict'
  }
}];

const data = $input.first().json;
const results = data.qdrantResults || [];
const chunkLimit = 800;
const totalContextLimit = 4000;

if (results.length === 0) {
  return [{
    json: {
      ...data,
      context: 'Nem található releváns dokumentum.',
      sources: [],
      sourceCount: 0,
      hasResults: false,
      snippets: []
    }
  }];
}

let totalChars = 0;
const contextParts = [];
const sources = [];
const snippets = [];

for (let i = 0; i < results.length; i++) {
  const d = results[i];
  const p = d.payload || {};
  const text = (p.text || p.summary || '').substring(0, chunkLimit);

  if (totalChars + text.length > totalContextLimit) break;

  contextParts.push(`#${i+1} FORRÁS: ${p.filename || 'ismeretlen'} (tag: ${p.tag || '-'})\n${text}\n---`);
  sources.push({
    index: i + 1,
    filename: p.filename || 'ismeretlen',
    tag: p.tag || '-',
    score: Math.round((d.score || 0) * 100) / 100,
    department: p.department || '-'
  });
  snippets.push(text.substring(0, 200));
  totalChars += text.length;
}

return [{
  json: {
    ...data,
    context: contextParts.join('\n\n'),
    sources,
    sourceCount: sources.length,
    hasResults: true,
    snippets
  }
}];

