const input = $input.first().json;

// ctx = minden, amit eddig külön node-ból szedtél
const ctx = input;
const llmResp = input;

// --- ANSWER ---
const answer = (llmResp.message?.content || 'Hiba történt a válasz generálása során.').trim();

// --- RAG ADATOK ---
const sources = ctx.sources || [];
const snippets = ctx.snippets || [];
const count = ctx.sourceCount || sources.length || 0;

// --- CONFIDENCE ---
let confidence = 0.0;

if (!ctx.hasResults) confidence = 0.0;
else if (ctx.retrievalMode === 'strict' && count >= 4) confidence = 0.92;
else if (ctx.retrievalMode === 'strict' && count === 3) confidence = 0.84;
else if (ctx.retrievalMode === 'strict' && count === 2) confidence = 0.74;
else if (ctx.retrievalMode === 'strict' && count === 1) confidence = 0.60;
else if (ctx.retrievalMode === 'relaxed' && count >= 3) confidence = 0.72;
else if (ctx.retrievalMode === 'relaxed' && count === 2) confidence = 0.62;
else if (ctx.retrievalMode === 'relaxed' && count === 1) confidence = 0.50;

// --- CITATION ---
const citationBlock = sources.length
  ? sources.map(s => 
      `  [#${s.index ?? 1}] ${s.filename || 'unknown'} (${s.tag || '-'}, relevancia: ${Math.round((s.score || 0.8) * 100)}%)`
    ).join('\n')
  : '  Nem található forrás.';

// --- LATENCY ---
const durationMs = Date.now() - (ctx.startedAtMs || Date.now());

// --- FORMATTED ---
const formattedAnswer = `${answer}

📎 Felhasznált források:
${citationBlock}

🎯 Megbízhatóság: ${Math.round(confidence * 100)}%
⏱ Feldolgozási idő: ${durationMs} ms`;

// --- OUTPUT ---
return [{
  json: {
    ...ctx,
    answer,
    formattedAnswer,
    confidence,
    confidencePct: Math.round(confidence * 100),
    citationBlock,
    sourceFilenames: sources.map(s => s.filename),
    durationMs,
    snippets
  }
}];

const embedding = $json.data?.[0]?.embedding;

if (!embedding) {
  throw new Error("Embedding not found in OpenAI response");
}

return [{
  json: {
    ...$json,
    embedding
  }
}];
